.leader-link{
  text-decoration:none;
  color:#fff;
  display:block;
}

.leader-link:hover{
  color:#fff;
}

.leader-card{
  background:#181818;
  border-radius:15px;
  overflow:hidden;
  transition:.4s ease;
  border:1px solid rgba(255,255,255,.05);
}

.leader-card:hover{
  transform:translateY(-8px);
  box-shadow:0 15px 40px rgba(0,0,0,.4);
}

.leader-card img{
  width:100%;
  height:350px;
  object-fit:cover;
}
